#[tokio::test]
async fn receive_pack_capacity_exhaustion_returns_backpressure() {
    let state = state_with_budget_config(RuntimeBudgetConfig {
        receive_pack_concurrency: 0,
        ..Default::default()
    });
    let secret = "scope_git_budget_test";
    {
