   666	    if !output.status.success() {
   667	        return Err(ApiError::service_unavailable(format!(
   668	            "git upload-pack failed: {}",
   669	            truncated_git_stderr(&output.stderr)
   670	        )));
   671	    }
   672	
   673	    Ok(git_response(
   674	        "application/x-git-upload-pack-result",
   675	        output.stdout,
   676	    ))
   677	}
   678	
   679	pub(crate) fn git_upload_pack_advertisement(repo_path: &FsPath, timeout: Duration) -> Response {
   680	    match git_command_output_with_timeout(
   681	        Command::new("git")
   682	            .arg("upload-pack")
   683	            .arg("--stateless-rpc")
   684	            .arg("--advertise-refs")
   685	            .arg(repo_path),
   686	        None,
   687	        timeout,
   688	    ) {
   689	        Ok(advertisement) => {
   690	            let mut body = pkt_line(format!("# service={GIT_UPLOAD_PACK}\n").as_bytes());
   691	            body.extend_from_slice(b"0000");
   692	            body.extend(advertisement);
   693	            git_response("application/x-git-upload-pack-advertisement", body)
   694	        }
   695	        Err(error) => git_advertisement_error(error.message),
   696	    }
   697	}
   698	
   699	pub(crate) fn git_response(content_type: &'static str, body: Vec<u8>) -> Response {
   700	    (
   701	        StatusCode::OK,
   702	        [(CONTENT_TYPE, content_type), (CACHE_CONTROL, "no-cache")],
   703	        Body::from(body),
   704	    )
   705	        .into_response()
   706	}
   707	
   708	pub(crate) fn git_advertisement_error(message: impl AsRef<str>) -> Response {
   709	    git_response(
   710	        "application/x-git-upload-pack-advertisement",
   711	        git_error_body(message.as_ref()),
   712	    )
   713	}
   714	
   715	pub(crate) fn git_upload_pack_error(message: impl AsRef<str>) -> Response {
   716	    git_response(
   717	        "application/x-git-upload-pack-result",
   718	        git_error_body(message.as_ref()),
   719	    )
   720	}
   721	
   722	pub(crate) fn git_error_body(message: &str) -> Vec<u8> {
   723	    pkt_line(format!("ERR {message}\n").as_bytes())
   724	}
   725	
   726	pub(crate) fn pkt_line(payload: &[u8]) -> Vec<u8> {
   727	    let len = payload.len() + 4;
   728	    let mut line = format!("{len:04x}").into_bytes();
   729	    line.extend_from_slice(payload);
   730	    line
   731	}
